create table if not exists public.skd_lookup (
  code text primary key,
  normalized_code text not null unique,
  level integer not null,
  section_code text,
  descriptor_sl text not null,
  descriptor_en text,
  parent_code text,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create index if not exists skd_lookup_level_idx on public.skd_lookup(level);
create index if not exists skd_lookup_section_idx on public.skd_lookup(section_code);
create index if not exists skd_lookup_parent_idx on public.skd_lookup(parent_code);

